// website-promo.component.ts
import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { PublicRestaurant, RestaurantPublicService } from '../../services/restaurant-public.service';
import { ActivatedRoute } from '@angular/router';
import { LucideAngularModule } from 'lucide-angular';

interface Feature {
  icon: string;
  title: string;
  description: string;
  color: string;
}

interface Step {
  number: string;
  title: string;
  description: string;
}

@Component({
  selector: 'app-web-site',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './web-site.html',
  styleUrls: ['../../../promo-common.css']
})
export class WebSite implements OnInit {

  private route = inject(ActivatedRoute);
  private restaurantPublicService = inject(RestaurantPublicService);
  loading = true;
  logoError = false;  
  restaurant: PublicRestaurant | null = null;   

  
async ngOnInit() {
  // Prima prova dal route
  const restaurantId = this.route.snapshot.paramMap.get('id');
  
  if (restaurantId) {
    this.loadRestaurant(restaurantId);
  } else {
    // Fallback: prende l'ID dal ristorante dell'utente loggato
    const id = await this.restaurantPublicService.getCurrentRestaurantId();
    if (id) {
      this.loadRestaurant(id);
    } else {
      console.warn('⚠️ Nessun ristorante trovato');
      this.loading = false;
    }
  }
}

async loadRestaurant(restaurantId: string) {
  try {
    this.loading = true;
    console.log('⏳ Caricamento ristorante con ID:', restaurantId);
    this.restaurant = await this.restaurantPublicService.loadRestaurantById(restaurantId);
    console.log('✅ Ristorante caricato:', this.restaurant);
    console.log('🖼️ Logo URL ricevuto:', this.restaurant?.logo_url);
  } catch (error) {
    console.error('❌ Errore nel caricamento:', error);
  } finally {
    this.loading = false;
    console.log('🏁 Caricamento completato, loading = false');
  }
}

  onLogoError(event: Event) {
    this.logoError = true;  // Segnala che il caricamento dell'immagine è fallito
  }


  contactForm = {
    name: '',
    email: '',
    phone: '',
    message: ''
  };

features: Feature[] = [
  {
    icon: 'Link',
    title: 'Integrazione Totale',
    description: 'Il tuo sito dialoga con Promethea: prenotazioni, menu e disponibilità sempre sincronizzati in tempo reale.',
    color: 'var(--primary)'
  },
  {
    icon: 'Zap',
    title: 'Zero Complessità',
    description: "Nessuna gestione tecnica. Aggiorni l'app, si aggiorna il sito. Semplice come dev'essere.",
    color: 'var(--tertiary)'
  },
  {
    icon: 'Palette',
    title: 'Design Su Misura',
    description: 'Non un template standard, ma un sito che rispecchia la tua identità e la tua cucina.',
    color: 'var(--secondary)'
  },
  {
    icon: 'Smartphone',
    title: 'Mobile First',
    description: 'I tuoi clienti cercano su smartphone. Il sito è ottimizzato per convertire da mobile.',
    color: 'var(--primary)'
  }
];

  steps: Step[] = [
    {
      number: '01',
      title: 'Analizziamo',
      description: 'Studiamo il tuo brand, il tuo menu e i tuoi obiettivi. Un colloquio, non un form.'
    },
    {
      number: '02',
      title: 'Creiamo',
      description: 'Il nostro team sviluppa il sito integrato con i tuoi dati Promethea esistenti.'
    },
    {
      number: '03',
      title: 'Lanciamo',
      description: 'Online in 2-3 settimane. Da quel momento, ogni modifica nell\'app si riflette sul sito.'
    }
  ];

modules = [
  { name: 'Prenotazioni Online', color: '#9F1893', icon: 'CalendarDays' },
  { name: 'Menu Digitale', color: '#A50063', icon: 'UtensilsCrossed' },
  { name: 'Gestione Tavoli', color: '#EF0095', icon: 'Armchair' },
  { name: 'Recensioni', color: '#0F0F0F', icon: 'Star' }
];

  showSuccessMessage = false;

  onSubmit() {
    // Qui implementerai l'invio reale
    console.log('Form inviato:', this.contactForm);
    
    this.showSuccessMessage = true;
    setTimeout(() => {
      this.showSuccessMessage = false;
      this.resetForm();
    }, 3000);
  }

  resetForm() {
    this.contactForm = {
      name: '',
      email: '',
      phone: '',
      message: ''
    };
  }


}